453		private SpringApplicationRunListeners getRunListeners(String[] args) {
454			ArgumentResolver argumentResolver = ArgumentResolver.of(SpringApplication.class, this);
455			argumentResolver = argumentResolver.and(String[].class, args);
456			List<SpringApplicationRunListener> listeners = getSpringFactoriesInstances(SpringApplicationRunListener.class,
457					argumentResolver);
458			SpringApplicationHook hook = applicationHook.get();
459			SpringApplicationRunListener hookListener = (hook != null) ? hook.getRunListener(this) : null;
460			if (hookListener != null) {
461				listeners = new ArrayList<>(listeners);
462				listeners.add(hookListener);
463			}
464			return new SpringApplicationRunListeners(logger, listeners, this.applicationStartup);
465		}
466	
467		private <T> List<T> getSpringFactoriesInstances(Class<T> type) {
468			return getSpringFactoriesInstances(type, null);
469		}
470	
471		private <T> List<T> getSpringFactoriesInstances(Class<T> type, @Nullable ArgumentResolver argumentResolver) {
472			return SpringFactoriesLoader.forDefaultResourceLocation(getClassLoader()).load(type, argumentResolver);
473		}
474	
475		private ConfigurableEnvironment getOrCreateEnvironment() {
476			if (this.environment != null) {
477				return this.environment;
478			}
479			WebApplicationType webApplicationType = this.properties.getWebApplicationType();
480			ConfigurableEnvironment environment = this.applicationContextFactory.createEnvironment(webApplicationType);
481			if (environment == null && this.applicationContextFactory != ApplicationContextFactory.DEFAULT) {
482				environment = ApplicationContextFactory.DEFAULT.createEnvironment(webApplicationType);
483			}
484			return (environment != null) ? environment : new ApplicationEnvironment();
485		}
486	
487		/**
488		 * Template method delegating to
489		 * {@link #configurePropertySources(ConfigurableEnvironment, String[])} and
490		 * {@link #configureProfiles(ConfigurableEnvironment, String[])} in that order.
491		 * Override this method for complete control over Environment customization, or one of
492		 * the above for fine-grained control over property sources or profiles, respectively.
493		 * @param environment this application's environment
494		 * @param args arguments passed to the {@code run} method
495		 * @see #configureProfiles(ConfigurableEnvironment, String[])
496		 * @see #configurePropertySources(ConfigurableEnvironment, String[])
497		 */
498		protected void configureEnvironment(ConfigurableEnvironment environment, String[] args) {
499			if (this.addConversionService) {
500				environment.setConversionService(new ApplicationConversionService());
501			}
502			configurePropertySources(environment, args);
503			configureProfiles(environment, args);
504		}
505	
506		/**
507		 * Add, remove or re-order any {@link PropertySource}s in this application's
508		 * environment.
509		 * @param environment this application's environment
510		 * @param args arguments passed to the {@code run} method
511		 * @see #configureEnvironment(ConfigurableEnvironment, String[])
512		 */
513		protected void configurePropertySources(ConfigurableEnvironment environment, String[] args) {
514			MutablePropertySources sources = environment.getPropertySources();
515			if (!CollectionUtils.isEmpty(this.defaultProperties)) {
516				DefaultPropertiesPropertySource.addOrMerge(this.defaultProperties, sources);
517			}
518			if (this.addCommandLineProperties && args.length > 0) {
519				String name = CommandLinePropertySource.COMMAND_LINE_PROPERTY_SOURCE_NAME;
520				PropertySource<?> source = sources.get(name);
521				if (source != null) {
522					CompositePropertySource composite = new CompositePropertySource(name);
523					composite
524						.addPropertySource(new SimpleCommandLinePropertySource("springApplicationCommandLineArgs", args));
525					composite.addPropertySource(source);
526					sources.replace(name, composite);
527				}
528				else {
529					sources.addFirst(new SimpleCommandLinePropertySource(args));
530				}
531			}
532			environment.getPropertySources().addLast(new ApplicationInfoPropertySource(this.mainApplicationClass));
533		}
