536		 * Configure which profiles are active (or active by default) for this application
537		 * environment. Additional profiles may be activated during configuration file
538		 * processing through the {@code spring.profiles.active} property.
539		 * @param environment this application's environment
540		 * @param args arguments passed to the {@code run} method
541		 * @see #configureEnvironment(ConfigurableEnvironment, String[])
542		 */
543		protected void configureProfiles(ConfigurableEnvironment environment, String[] args) {
544		}
