546		/**
547		 * Bind the environment to the {@link ApplicationProperties}.
548		 * @param environment the environment to bind
549		 */
550		protected void bindToSpringApplication(ConfigurableEnvironment environment) {
551			try {
552				Binder.get(environment).bind("spring.main", Bindable.ofInstance(this.properties));
553			}
554			catch (Exception ex) {
555				throw new IllegalStateException("Cannot bind to SpringApplication", ex);
556			}
557		}
558	
559		private @Nullable Banner printBanner(ConfigurableEnvironment environment) {
560			if (this.properties.getBannerMode(environment) == Banner.Mode.OFF) {
561				return null;
562			}
563			ResourceLoader resourceLoader = (this.resourceLoader != null) ? this.resourceLoader
564					: new DefaultResourceLoader(null);
565			SpringApplicationBannerPrinter bannerPrinter = new SpringApplicationBannerPrinter(resourceLoader, this.banner);
566			if (this.properties.getBannerMode(environment) == Mode.LOG) {
567				return bannerPrinter.print(environment, this.mainApplicationClass, logger);
568			}
569			return bannerPrinter.print(environment, this.mainApplicationClass, System.out);
570		}
571	
572		/**
573		 * Strategy method used to create the {@link ApplicationContext}. By default this
574		 * method will respect any explicitly set application context class or factory before
575		 * falling back to a suitable default.
576		 * @return the application context (not yet refreshed)
577		 * @see #setApplicationContextFactory(ApplicationContextFactory)
578		 */
579		protected ConfigurableApplicationContext createApplicationContext() {
580			ConfigurableApplicationContext context = this.applicationContextFactory
581				.create(this.properties.getWebApplicationType());
582			Assert.state(context != null, "ApplicationContextFactory created null context");
583			return context;
584		}
