655				else {
656					String message = (activeProfiles.size() == 1) ? "1 profile is active: "
657							: activeProfiles.size() + " profiles are active: ";
658					log.info("The following " + message + StringUtils.collectionToDelimitedString(activeProfiles, ", "));
659				}
660			}
661		}
