830		private Collection<SpringBootExceptionReporter> getExceptionReporters(
831				@Nullable ConfigurableApplicationContext context) {
832			try {
833				ArgumentResolver argumentResolver = (context != null)
834						? ArgumentResolver.of(ConfigurableApplicationContext.class, context) : ArgumentResolver.none();
835				return getSpringFactoriesInstances(SpringBootExceptionReporter.class, argumentResolver);
836			}
837			catch (Throwable ex) {
838				return Collections.emptyList();
839			}
840		}
841	
842		private void reportFailure(Collection<SpringBootExceptionReporter> exceptionReporters, Throwable failure) {
843			try {
844				for (SpringBootExceptionReporter reporter : exceptionReporters) {
845					if (reporter.reportException(failure)) {
846						registerLoggedException(failure);
847						return;
848					}
849				}
850			}
851			catch (Throwable ex) {
852				// Continue with normal handling of the original failure
853			}
854			if (logger.isErrorEnabled()) {
855				if (NativeDetector.inNativeImage()) {
856					// Depending on how early the failure was, logging may not work in a
857					// native image so we output the stack trace directly to System.out
858					// instead.
859					System.out.println("Application run failed");
860					failure.printStackTrace(System.out);
861				}
862				else {
863					logger.error("Application run failed", failure);
864				}
865				registerLoggedException(failure);
866			}
867		}
