1384		/**
1385		 * Static helper that can be used to exit a {@link SpringApplication} and obtain a
1386		 * code indicating success (0) or otherwise. Does not throw exceptions but should
1387		 * print stack traces of any encountered. Applies the specified
1388		 * {@link ExitCodeGenerator ExitCodeGenerators} in addition to any Spring beans that
1389		 * implement {@link ExitCodeGenerator}. When multiple generators are available, the
1390		 * first non-zero exit code is used. Generators are ordered based on their
1391		 * {@link Ordered} implementation and {@link Order @Order} annotation.
1392		 * @param context the context to close if possible
1393		 * @param exitCodeGenerators exit code generators
1394		 * @return the outcome (0 if successful)
1395		 */
1396		public static int exit(ApplicationContext context, ExitCodeGenerator... exitCodeGenerators) {
1397			Assert.notNull(context, "'context' must not be null");
1398			int exitCode = 0;
1399			try {
1400				try {
1401					ExitCodeGenerators generators = new ExitCodeGenerators();
1402					Collection<ExitCodeGenerator> beans = context.getBeansOfType(ExitCodeGenerator.class).values();
1403					generators.addAll(exitCodeGenerators);
1404					generators.addAll(beans);
1405					exitCode = generators.getExitCode();
1406					if (exitCode != 0) {
1407						context.publishEvent(new ExitCodeEvent(context, exitCode));
1408					}
1409				}
1410				finally {
1411					close(context);
1412				}
1413			}
1414			catch (Exception ex) {
1415				ex.printStackTrace();
1416				exitCode = (exitCode != 0) ? exitCode : 1;
1417			}
1418			return exitCode;
1419		}
