38	import org.springframework.boot.EnvironmentPostProcessor;
39	import org.springframework.boot.SpringApplication;
40	import org.springframework.boot.bootstrap.ConfigurableBootstrapContext;
41	import org.springframework.boot.context.event.ApplicationEnvironmentPreparedEvent;
42	import org.springframework.boot.context.event.ApplicationFailedEvent;
43	import org.springframework.boot.context.event.ApplicationPreparedEvent;
44	import org.springframework.boot.logging.DeferredLogs;
45	import org.springframework.context.ApplicationEvent;
46	import org.springframework.context.ConfigurableApplicationContext;
47	import org.springframework.context.event.SmartApplicationListener;
48	import org.springframework.core.Ordered;
49	import org.springframework.core.env.ConfigurableEnvironment;
50	import org.springframework.core.env.Environment;
51	import org.springframework.core.io.ResourceLoader;
52	import org.springframework.javapoet.CodeBlock;
53	import org.springframework.util.Assert;
54	import org.springframework.util.ClassUtils;
55	import org.springframework.util.ObjectUtils;
56	
57	/**
58	 * {@link SmartApplicationListener} used to trigger {@link EnvironmentPostProcessor
59	 * EnvironmentPostProcessors} registered in the {@code spring.factories} file.
60	 *
61	 * @author Phillip Webb
62	 * @author Stephane Nicoll
63	 * @since 4.0.0
64	 */
65	public class EnvironmentPostProcessorApplicationListener implements SmartApplicationListener, Ordered {
66	
67		static final String AOT_FEATURE_NAME = "EnvironmentPostProcessor";
68	
69		/**
70		 * The default order for the processor.
71		 */
72		public static final int DEFAULT_ORDER = Ordered.HIGHEST_PRECEDENCE + 10;
73	
74		private final DeferredLogs deferredLogs;
75	
76		private int order = DEFAULT_ORDER;
77	
78		private final Function<@Nullable ClassLoader, EnvironmentPostProcessorsFactory> postProcessorsFactory;
79	
80		/**
81		 * Create a new {@link EnvironmentPostProcessorApplicationListener} with
82		 * {@link EnvironmentPostProcessor} classes loaded through {@code spring.factories}.
83		 */
84		public EnvironmentPostProcessorApplicationListener() {
85			this(EnvironmentPostProcessorsFactory::fromSpringFactories);
86		}
87	
88		/**
89		 * Create a new {@link EnvironmentPostProcessorApplicationListener} with post
90		 * processors created by the given factory.
91		 * @param postProcessorsFactory the post processors factory
92		 */
93		private EnvironmentPostProcessorApplicationListener(
94				Function<@Nullable ClassLoader, EnvironmentPostProcessorsFactory> postProcessorsFactory) {
95			this.postProcessorsFactory = postProcessorsFactory;
96			this.deferredLogs = new DeferredLogs();
97		}
98	
99		/**
100		 * Factory method that creates an {@link EnvironmentPostProcessorApplicationListener}
101		 * with a specific {@link EnvironmentPostProcessorsFactory}.
102		 * @param postProcessorsFactory the environment post processor factory
103		 * @return an {@link EnvironmentPostProcessorApplicationListener} instance
104		 */
105		public static EnvironmentPostProcessorApplicationListener with(
106				EnvironmentPostProcessorsFactory postProcessorsFactory) {
107			return new EnvironmentPostProcessorApplicationListener((classloader) -> postProcessorsFactory);
108		}
109	
110		@Override
111		public boolean supportsEventType(Class<? extends ApplicationEvent> eventType) {
112			return ApplicationEnvironmentPreparedEvent.class.isAssignableFrom(eventType)
113					|| ApplicationPreparedEvent.class.isAssignableFrom(eventType)
114					|| ApplicationFailedEvent.class.isAssignableFrom(eventType);
115		}
116	
117		@Override
118		public void onApplicationEvent(ApplicationEvent event) {
119			if (event instanceof ApplicationEnvironmentPreparedEvent environmentPreparedEvent) {
120				onApplicationEnvironmentPreparedEvent(environmentPreparedEvent);
121			}
122			if (event instanceof ApplicationPreparedEvent) {
123				onApplicationPreparedEvent();
124			}
125			if (event instanceof ApplicationFailedEvent) {
126				onApplicationFailedEvent();
127			}
128		}
129	
130		private void onApplicationEnvironmentPreparedEvent(ApplicationEnvironmentPreparedEvent event) {
131			ConfigurableEnvironment environment = event.getEnvironment();
132			SpringApplication application = event.getSpringApplication();
133			List<EnvironmentPostProcessor> postProcessors = getEnvironmentPostProcessors(application.getResourceLoader(),
134					event.getBootstrapContext());
135			addAotGeneratedEnvironmentPostProcessorIfNecessary(postProcessors, application);
136			for (EnvironmentPostProcessor postProcessor : postProcessors) {
137				postProcessor.postProcessEnvironment(environment, application);
138			}
139		}
140	
141		private void onApplicationPreparedEvent() {
142			finish();
143		}
144	
145		private void onApplicationFailedEvent() {
146			finish();
147		}
148	
149		private void finish() {
150			this.deferredLogs.switchOverAll();
151		}
152	
153		List<EnvironmentPostProcessor> getEnvironmentPostProcessors(@Nullable ResourceLoader resourceLoader,
154				ConfigurableBootstrapContext bootstrapContext) {
155			ClassLoader classLoader = (resourceLoader != null) ? resourceLoader.getClassLoader() : null;
156			EnvironmentPostProcessorsFactory postProcessorsFactory = this.postProcessorsFactory.apply(classLoader);
157			return postProcessorsFactory.getEnvironmentPostProcessors(this.deferredLogs, bootstrapContext);
158		}
159	
160		private void addAotGeneratedEnvironmentPostProcessorIfNecessary(List<EnvironmentPostProcessor> postProcessors,
161				SpringApplication springApplication) {
162			if (AotDetector.useGeneratedArtifacts()) {
163				ClassLoader classLoader = (springApplication.getResourceLoader() != null)
164						? springApplication.getResourceLoader().getClassLoader() : null;
165				Class<?> mainApplicationClass = springApplication.getMainApplicationClass();
166				Assert.state(mainApplicationClass != null, "mainApplicationClass not found");
167				String postProcessorClassName = mainApplicationClass.getName() + "__" + AOT_FEATURE_NAME;
168				if (ClassUtils.isPresent(postProcessorClassName, classLoader)) {
169					postProcessors.add(0, instantiateEnvironmentPostProcessor(postProcessorClassName, classLoader));
170				}
171			}
172		}
173	
174		private EnvironmentPostProcessor instantiateEnvironmentPostProcessor(String postProcessorClassName,
175				@Nullable ClassLoader classLoader) {
176			try {
177				Class<?> initializerClass = ClassUtils.resolveClassName(postProcessorClassName, classLoader);
178				Assert.isAssignable(EnvironmentPostProcessor.class, initializerClass);
179				return (EnvironmentPostProcessor) BeanUtils.instantiateClass(initializerClass);
180			}
181			catch (BeanInstantiationException ex) {
182				throw new IllegalArgumentException(
183						"Failed to instantiate EnvironmentPostProcessor: " + postProcessorClassName, ex);
184			}
185		}
186	
187		@Override
188		public int getOrder() {
189			return this.order;
190		}
191	
192		public void setOrder(int order) {
193			this.order = order;
194		}
195	
196		/**
197		 * Contribute a {@code <Application>__EnvironmentPostProcessor} class that stores AOT
198		 * optimizations.
199		 */
200		static class EnvironmentBeanFactoryInitializationAotProcessor implements BeanFactoryInitializationAotProcessor {
201	
202			@Override
203			public @Nullable BeanFactoryInitializationAotContribution processAheadOfTime(
204					ConfigurableListableBeanFactory beanFactory) {
205				Environment environment = beanFactory.getBean(ConfigurableApplicationContext.ENVIRONMENT_BEAN_NAME,
206						Environment.class);
207				String[] activeProfiles = environment.getActiveProfiles();
208				String[] defaultProfiles = environment.getDefaultProfiles();
209				if (!ObjectUtils.isEmpty(activeProfiles) && !Arrays.equals(activeProfiles, defaultProfiles)) {
210					return new EnvironmentAotContribution(activeProfiles);
211				}
212				return null;
213			}
214	
215		}
216	
217		private static final class EnvironmentAotContribution implements BeanFactoryInitializationAotContribution {
218	
219			private static final String ENVIRONMENT_VARIABLE = "environment";
220	
221			private final String[] activeProfiles;
222	
223			private EnvironmentAotContribution(String[] activeProfiles) {
224				this.activeProfiles = activeProfiles;
225			}
226	
227			@Override
228			public void applyTo(GenerationContext generationContext,
229					BeanFactoryInitializationCode beanFactoryInitializationCode) {
230				GeneratedClass generatedClass = generationContext.getGeneratedClasses()
231					.addForFeature(AOT_FEATURE_NAME, (type) -> {
232						type.addModifiers(Modifier.PUBLIC);
233						type.addJavadoc("Configure the environment with AOT optimizations.");
234						type.addSuperinterface(EnvironmentPostProcessor.class);
235					});
236				generatedClass.getMethods().add("postProcessEnvironment", (method) -> {
237					method.addModifiers(Modifier.PUBLIC);
238					method.addAnnotation(Override.class);
239					method.addParameter(ConfigurableEnvironment.class, ENVIRONMENT_VARIABLE);
240					method.addParameter(SpringApplication.class, "application");
241					method.addCode(generateActiveProfilesInitializeCode());
242				});
243				generationContext.getRuntimeHints()
244					.reflection()
245					.registerType(GeneratedTypeReference.of(generatedClass.getName()),
246							MemberCategory.INVOKE_PUBLIC_CONSTRUCTORS);
247			}
248	
249			private CodeBlock generateActiveProfilesInitializeCode() {
250				CodeBlock.Builder code = CodeBlock.builder();
251				for (String activeProfile : this.activeProfiles) {
252					code.addStatement("$L.addActiveProfile($S)", ENVIRONMENT_VARIABLE, activeProfile);
253				}
254				return code.build();
255			}
256	
257		}
258	
259	}
